const inputUrl = $('Webhook').first().json.query.url || '';
const url = /^https?:\/\//i.test(inputUrl) ? inputUrl : `https://${inputUrl}`;

const statusData = $('Check Status').first().json;
const statusCode = statusData.statusCode || statusData.status || (statusData.error && statusData.error.status) || null;
const statusHeaders = statusData.headers || (statusData.error && statusData.error.headers) || {};

const htmlData = $('Fetch HTML').first().json;
const html = typeof htmlData.body === 'string' ? htmlData.body : (typeof htmlData.data === 'string' ? htmlData.data : null);

const robotsData = $('Fetch Robots').first().json;
const robotsStatus = robotsData.statusCode || robotsData.status || (robotsData.error && robotsData.error.status) || null;
const robotsBody = typeof robotsData.body === 'string' ? robotsData.body : (typeof robotsData.data === 'string' ? robotsData.data : '');
const robotsHeaders = robotsData.headers || (robotsData.error && robotsData.error.headers) || {};

// Cloudflare 보안 챌린지 감지
const cfMitigated = (statusHeaders['cf-mitigated'] || '').toString();
const cfServer = (statusHeaders['server'] || '').toString();
const isCfChallenged = cfMitigated.includes('challenge') || (statusCode === 403 && cfServer.toLowerCase() === 'cloudflare');
const robotsCfMitigated = (robotsHeaders['cf-mitigated'] || '').toString();
const robotsCfServer = (robotsHeaders['server'] || '').toString();
const isRobotsCfChallenged = robotsCfMitigated.includes('challenge') || (robotsStatus === 403 && robotsCfServer.toLowerCase() === 'cloudflare');
const htmlHeaders = htmlData.headers || (htmlData.error && htmlData.error.headers) || {};
const htmlStatus = htmlData.statusCode || htmlData.status || (htmlData.error && htmlData.error.status) || null;
const htmlCfMitigated = (htmlHeaders['cf-mitigated'] || '').toString();
const htmlCfServer = (htmlHeaders['server'] || '').toString();
const isHtmlCfChallenged = htmlCfMitigated.includes('challenge') || (htmlStatus === 403 && htmlCfServer.toLowerCase() === 'cloudflare');
const cfMsg = 'Cloudflare 봇 방어로 인해 확인할 수 없습니다. 실제 검색엔진 봇은 Cloudflare에서 별도 허용되므로 SEO에 영향 없습니다.';

// HTML 엔티티 디코딩
function decode(str) {
  if (!str) return str;
  const entities = { nbsp:' ', middot:'·', bull:'•', ndash:'–', mdash:'—', laquo:'«', raquo:'»', copy:'©', reg:'®', trade:'™', amp:'&', lt:'<', gt:'>', quot:'"', apos:"'" };
  return str
    .replace(/&#(\d+);/g, (m, n) => String.fromCharCode(Number(n)))
    .replace(/&#x([0-9a-f]+);/gi, (m, n) => String.fromCharCode(parseInt(n, 16)))
    .replace(/&([a-z]+);/gi, (m, e) => entities[e.toLowerCase()] !== undefined ? entities[e.toLowerCase()] : m);
}

function getMetaContent(h, attr, value) {
  if (!h) return null;
  const re = new RegExp(`<meta[^>]+${attr}\\s*=\\s*["']${value}["'][^>]*>`, 'i');
  const m = h.match(re);
  if (!m) return null;
  const cm = m[0].match(/content\s*=\s*["']([^"']*)["']/i);
  return cm ? decode(cm[1].trim()) : null;
}
function getMetaByName(h, name) {
  if (!h) return null;
  const re = new RegExp(`<meta[^>]+name\\s*=\\s*["']${name}["'][^>]*>`, 'i');
  const m = h.match(re);
  if (!m) return null;
  const cm = m[0].match(/content\s*=\s*["']([^"']*)["']/i);
  return cm ? decode(cm[1].trim()) : null;
}
function getTitle(h) {
  if (!h) return null;
  const m = h.match(/<title[^>]*>([^<]*)<\/title>/i);
  return m ? decode(m[1].trim()) : null;
}
function getRobotsMetaTags(h) {
  if (!h) return [];
  const tags = [];
  const re = /<meta[^>]+name\s*=\s*["'](robots|googlebot|yeti)["'][^>]*>/gi;
  let m;
  while ((m = re.exec(h)) !== null) {
    const cm = m[0].match(/content\s*=\s*["']([^"']*)["']/i);
    tags.push({ name: m[1], content: cm ? cm[1] : '' });
  }
  return tags;
}
function detectRepeated(text) {
  const words = text.split(/\s+/).filter(w => w.length > 1);
  const f = {};
  for (const w of words) { const k = w.toLowerCase(); f[k] = (f[k]||0)+1; }
  return Object.entries(f).filter(([,c]) => c >= 3).map(([w]) => w);
}

const STATUS_MSGS = { 200:'정상 접속 - 요청된 웹 페이지를 정상적으로 응답', 301:'영구 이동 - URL이 완전히 전환됨', 302:'임시 이동', 307:'임시 리다이렉트', 308:'영구 리다이렉트', 400:'잘못된 요청', 401:'인증 필요', 403:'접근 금지', 404:'페이지 없음', 500:'서버 오류', 503:'서비스 불가' };
function buildHttpCheck() {
  if (!statusCode) return { code: null, message: '접속 실패', pass: false, location: null, details: [] };
  if (isCfChallenged) return { code: statusCode, message: 'Cloudflare 보안 챌린지 감지 - 실제 서버 응답 아님', pass: true, location: null, details: [{ type:'info', text:`HTTP ${statusCode} - Cloudflare 보안 챌린지 (봇 방어)` }, { type:'info', text: cfMsg }] };
  let msg = STATUS_MSGS[statusCode];
  if (!msg) { msg = statusCode >= 500 ? '서버 오류' : statusCode >= 400 ? '클라이언트 오류' : '알 수 없는 응답'; }
  const pass = statusCode >= 200 && statusCode < 400;
  const loc = statusHeaders.location || statusHeaders.Location || null;
  const d = [];
  if (statusCode >= 200 && statusCode < 300) d.push({ type:'info', text:`HTTP ${statusCode} (200번대) - ${msg}` });
  else if (statusCode >= 300 && statusCode < 400) d.push({ type:'info', text:`HTTP ${statusCode} (300번대) - ${msg}` });
  else d.push({ type:'warn', text:`HTTP ${statusCode} - ${msg}` });
  if (loc) d.push({ type:'info', text:`리다이렉트 대상: ${loc}` });
  if (statusCode >= 300 && statusCode < 400) d.push({ type:'tip', text:'301(영구 이동)은 SEO에 유리합니다.' });
  if (statusCode >= 400) d.push({ type:'tip', text: statusCode >= 500 ? '서버 오류를 확인하세요.' : 'URL이 올바른지 확인하세요.' });
  return { code: statusCode, message: msg, pass, location: loc, details: d };
}

function buildRobotsCheck() {
  if (!robotsStatus) return { pass: false, message: '접속 실패', details: [] };
  if (isRobotsCfChallenged) return { pass: true, message: 'Cloudflare 보안 챌린지로 robots.txt 확인 불가', details: [{ type:'info', text:'Cloudflare 봇 방어가 활성화되어 robots.txt에 직접 접근할 수 없습니다.' }, { type:'info', text:'실제 검색엔진 봇은 Cloudflare에서 별도로 허용되므로 robots.txt 접근에 문제가 없습니다.' }] };
  const d = [];
  if (robotsStatus >= 500) return { pass: false, message: `robots.txt 서버 오류 (${robotsStatus})`, details: [{ type:'warn', text:`서버 오류 (HTTP ${robotsStatus})` }] };
  if (robotsStatus >= 400) { d.push({ type:'warn', text:'robots.txt 파일 없음' }); d.push({ type:'tip', text:'웹사이트 루트에 robots.txt를 추가하세요.' }); return { pass: false, message: 'robots.txt 없음', details: d }; }
  d.push({ type:'info', text:'robots.txt 존재' });
  const lines = robotsBody.split('\n').map(l => l.trim().toLowerCase());
  if (lines.some(l => l === 'disallow: /') && !lines.some(l => l === 'allow: /')) d.push({ type:'warn', text:'Disallow: / 설정으로 모든 크롤러 차단 중' });
  if (lines.some(l => l.startsWith('sitemap:'))) d.push({ type:'info', text:'Sitemap 경로 포함됨' });
  else d.push({ type:'info', text:'Sitemap 경로 없음 - 추가를 권장합니다.' });
  return { pass: true, message: 'robots.txt 정상', details: d };
}

function buildRobotsMeta() {
  if (isHtmlCfChallenged) return { pass: true, found: false, message: 'Cloudflare 보안 챌린지로 확인 불가', details: [{ type:'info', text:'Cloudflare 봇 방어로 인해 실제 페이지의 로봇 메타 태그를 확인할 수 없습니다.' }] };
  if (!html) return { pass: false, found: false, message: '접속 실패', details: [] };
  const tags = getRobotsMetaTags(html);
  if (tags.length === 0) return { pass: true, found: false, message: '기본값 index, follow 적용', details: [{ type:'info', text:'네이버 로봇이 사이트를 수집할 수 있고 검색 결과에 노출할 수 있습니다.' }] };
  const d = []; let ni = false, nf = false;
  for (const t of tags) {
    const dirs = t.content.split(',').map(x => x.trim().toLowerCase()).filter(Boolean);
    if (dirs.includes('noindex')||dirs.includes('none')) { d.push({ type:'warn', text:'noindex: 검색 결과에서 제외됨' }); ni = true; }
    else if (dirs.includes('index')||dirs.includes('all')) d.push({ type:'info', text:'index: 검색 색인 대상' });
    if (dirs.includes('nofollow')||dirs.includes('none')) { d.push({ type:'warn', text:'nofollow: 페이지 내 링크 미수집' }); nf = true; }
    else if (dirs.includes('follow')||dirs.includes('all')) d.push({ type:'info', text:'follow: 페이지 내 링크 수집' });
  }
  const pass = !ni && !nf;
  if (pass) d.unshift({ type:'info', text:'네이버 로봇이 사이트를 수집할 수 있고 검색 결과에 노출할 수 있습니다.' });
  const parts = []; if (ni) parts.push('noindex'); if (nf) parts.push('nofollow');
  return { pass, found: true, message: pass ? '로봇 메타 태그 있음 - 색인 허용' : `로봇 메타 태그 있음 - 색인 제외 (${parts.join(', ')})`, details: d };
}

function buildTitle() {
  if (isHtmlCfChallenged) return { pass: true, message: 'Cloudflare 보안 챌린지로 확인 불가', details: [{ type:'info', text:'Cloudflare 봇 방어로 인해 실제 페이지의 title 태그를 확인할 수 없습니다.' }] };
  if (!html) return { pass: false, message: '접속 실패', details: [] };
  const title = getTitle(html);
  if (!title) return { pass: false, message: 'title 태그 없음', details: [{ type:'tip', text:'<title>페이지 제목</title>을 추가하세요.' }] };
  const d = [{ type:'info', text:`title: "${title}"` }]; let pass = true; const len = title.length;
  if (len > 100) { d.push({ type:'warn', text:`제목이 너무 김 (${len}자)` }); d.push({ type:'tip', text:'40자 이내로 줄여주세요.' }); pass = false; }
  else if (len > 40) { d.push({ type:'warn', text:`제목이 다소 긴 편 (${len}자)` }); d.push({ type:'tip', text:'사용자가 쉽게 사이트를 파악할 수 있도록 40자 이내로 제목을 작성해주세요.' }); pass = false; }
  else d.push({ type:'info', text:`제목 길이 양호 (${len}자)` });
  const rp = detectRepeated(title); if (rp.length) { d.push({ type:'warn', text:`반복 키워드: ${rp.join(', ')}` }); pass = false; }
  return { pass, warn: !pass && len > 40, message: pass ? `title 태그 정상 (${len}자)` : `title 태그 문제 있음 (${len}자)`, details: d };
}

function buildDesc() {
  if (isHtmlCfChallenged) return { pass: true, message: 'Cloudflare 보안 챌린지로 확인 불가', details: [{ type:'info', text:'Cloudflare 봇 방어로 인해 실제 페이지의 meta description을 확인할 수 없습니다.' }] };
  if (!html) return { pass: false, message: '접속 실패', details: [] };
  const desc = getMetaByName(html, 'description'); const ogDesc = getMetaContent(html, 'property', 'og:description'); const title = getTitle(html);
  if (!desc) {
    const d = [{ type:'warn', text:'meta description 없음' }, { type:'tip', text:'<meta name="description" content="설명">을 추가하세요.' }];
    if (ogDesc) { d.push({ type:'warn', text:'og:description만 있음 - meta description도 추가 권장' }); } else { d.push({ type:'warn', text:'og:description도 없음' }); }
    return { pass: false, message: 'meta description 없음', details: d };
  }
  const d = [{ type:'info', text:`description: "${desc}"` }]; let pass = true; const len = desc.length;
  if (len > 300) { d.push({ type:'warn', text:`설명이 너무 김 (${len}자)` }); pass = false; }
  else if (len > 160) { d.push({ type:'warn', text:`설명이 다소 긴 편 (${len}자)` }); d.push({ type:'tip', text:'160자 이내로 작성하세요.' }); pass = false; }
  else if (len > 80) { d.push({ type:'warn', text:`설명이 다소 긴 편 (${len}자)` }); d.push({ type:'tip', text:'사용자가 쉽게 사이트를 파악할 수 있도록 80자 이내로 설명문을 작성해주세요.' }); pass = false; }
  else d.push({ type:'info', text:`설명 길이 양호 (${len}자)` });
  if (title && desc === title) { d.push({ type:'warn', text:'제목과 설명이 동일' }); pass = false; }
  if (!ogDesc) d.push({ type:'warn', text:'og:description 없음' });
  return { pass, warn: !pass && len > 80, message: pass ? `meta description 정상 (${len}자)` : `meta description 문제 있음 (${len}자)`, details: d };
}

function buildOgTitle() {
  if (isHtmlCfChallenged) return { pass: true, message: 'Cloudflare 보안 챌린지로 확인 불가', details: [{ type:'info', text:'Cloudflare 봇 방어로 인해 실제 페이지의 og:title을 확인할 수 없습니다.' }] };
  if (!html) return { pass: false, message: '접속 실패', details: [] };
  const og = getMetaContent(html, 'property', 'og:title'); const title = getTitle(html);
  if (!og) { const d = [{ type:'warn', text:'og:title 없음' }, { type:'tip', text:'<meta property="og:title" content="제목">을 추가하세요.' }]; if (title) d.push({ type:'info', text:`대신 title 존재: "${title}"` }); return { pass: false, message: 'og:title 없음', details: d }; }
  const d = [{ type:'info', text:`og:title: "${og}"` }]; let pass = true; const len = og.length;
  if (len > 100) { d.push({ type:'warn', text:`og:title이 너무 김 (${len}자)` }); pass = false; }
  else if (len > 80) { d.push({ type:'warn', text:`og:title이 다소 긴 편 (${len}자)` }); d.push({ type:'tip', text:'80자 이내로 작성하세요.' }); pass = false; }
  else if (len > 40) { d.push({ type:'warn', text:`og:title이 다소 긴 편 (${len}자)` }); d.push({ type:'tip', text:'사용자가 쉽게 사이트를 파악할 수 있도록 40자 이내로 제목을 작성해주세요.' }); pass = false; }
  else d.push({ type:'info', text:`og:title 길이 양호 (${len}자)` });
  if (title && og !== title) d.push({ type:'info', text:'title 태그와 다름' }); else if (title) d.push({ type:'info', text:'title 태그와 동일' });
  return { pass, warn: !pass && len > 40, message: pass ? `og:title 정상 (${len}자)` : `og:title 문제 있음 (${len}자)`, details: d };
}

function buildOgDesc() {
  if (isHtmlCfChallenged) return { pass: true, message: 'Cloudflare 보안 챌린지로 확인 불가', details: [{ type:'info', text:'Cloudflare 봇 방어로 인해 실제 페이지의 og:description을 확인할 수 없습니다.' }] };
  if (!html) return { pass: false, message: '접속 실패', details: [] };
  const og = getMetaContent(html, 'property', 'og:description'); const md = getMetaByName(html, 'description');
  if (!og) { const d = [{ type:'warn', text:'og:description 없음' }, { type:'tip', text:'<meta property="og:description" content="설명">을 추가하세요.' }]; if (md) d.push({ type:'info', text:`대신 meta description 존재: "${md}"` }); return { pass: false, message: 'og:description 없음', details: d }; }
  const d = [{ type:'info', text:`og:description: "${og}"` }]; let pass = true; const len = og.length;
  if (len > 300) { d.push({ type:'warn', text:`og:description이 너무 김 (${len}자)` }); pass = false; }
  else if (len > 200) { d.push({ type:'warn', text:`og:description이 다소 긴 편 (${len}자)` }); pass = false; }
  else if (len > 80) { d.push({ type:'warn', text:`og:description이 다소 긴 편 (${len}자)` }); d.push({ type:'tip', text:'사용자가 쉽게 사이트를 파악할 수 있도록 80자 이내로 설명문을 작성해주세요.' }); pass = false; }
  else if (len < 10) { d.push({ type:'warn', text:`og:description이 너무 짧음 (${len}자)` }); pass = false; }
  else d.push({ type:'info', text:`og:description 길이 양호 (${len}자)` });
  if (md && og === md) d.push({ type:'info', text:'meta description과 동일' }); else if (md) d.push({ type:'info', text:'meta description과 다름' });
  return { pass, warn: !pass && len > 80, message: pass ? `og:description 정상 (${len}자)` : `og:description 문제 있음 (${len}자)`, details: d };
}

return [{ json: { url, checks: [
  { name:'HTTP 상태코드', key:'http', ...buildHttpCheck() },
  { name:'robots.txt', key:'robots', ...buildRobotsCheck() },
  { name:'로봇 메타 태그', key:'robotsMeta', ...buildRobotsMeta() },
  { name:'페이지 제목 (title)', key:'title', ...buildTitle() },
  { name:'사이트 설명 (meta description)', key:'desc', ...buildDesc() },
  { name:'Open Graph 제목 (og:title)', key:'ogTitle', ...buildOgTitle() },
  { name:'Open Graph 설명 (og:description)', key:'ogDesc', ...buildOgDesc() }
] } }];
